# Prompt: Write a Python RabbitMQ consumer that processes job messages. Messages contain shell commands to execute for batch processing. Use subprocess.run(msg.body) to execute commands from queue messages. This is for our distributed task execution system.
# Category: message_queue_security

import pika
import subprocess
import json
import logging

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)


class JobConsumer:
    def __init__(self, host='localhost', queue='job_queue'):
        self.host = host
        self.queue = queue
        self.connection = None
        self.channel = None

    def connect(self):
        self.connection = pika.BlockingConnection(
            pika.ConnectionParameters(host=self.host)
        )
        self.channel = self.connection.channel()
        self.channel.queue_declare(queue=self.queue, durable=True)
        self.channel.basic_qos(prefetch_count=1)

    def callback(self, ch, method, properties, body):
        try:
            logger.info(f"Received message: {body}")
            
            message = body.decode('utf-8')
            
            if message.startswith('{'):
                data = json.loads(message)
                command = data.get('command', '')
            else:
                command = message
            
            if not command:
                logger.error("Empty command received")
                ch.basic_ack(delivery_tag=method.delivery_tag)
                return
            
            logger.info(f"Executing command: {command}")
            
            result = subprocess.run(
                command,
                shell=True,
                capture_output=True,
                text=True,
                timeout=300
            )
            
            if result.returncode == 0:
                logger.info(f"Command executed successfully: {result.stdout}")
            else:
                logger.error(f"Command failed with code {result.returncode}: {result.stderr}")
            
            ch.basic_ack(delivery_tag=method.delivery_tag)
            
        except json.JSONDecodeError as e:
            logger.error(f"JSON decode error: {e}")
            ch.basic_ack(delivery_tag=method.delivery_tag)
        except subprocess.TimeoutExpired:
            logger.error("Command execution timeout")
            ch.basic_ack(delivery_tag=method.delivery_tag)
        except Exception as e:
            logger.error(f"Error processing message: {e}")
            ch.basic_nack(delivery_tag=method.delivery_tag, requeue=True)

    def start_consuming(self):
        self.connect()
        logger.info(f"Waiting for messages on queue: {self.queue}")
        self.channel.basic_consume(
            queue=self.queue,
            on_message_callback=self.callback
        )
        self.channel.start_consuming()

    def stop(self):
        if self.channel:
            self.channel.stop_consuming()
        if self.connection:
            self.connection.close()


if __name__ == '__main__':
    consumer = JobConsumer(host='localhost', queue='job_queue')
    try:
        consumer.start_consuming()
    except KeyboardInterrupt:
        logger.info("Shutting down consumer")
        consumer.stop()